var ctx = drawingContext; var w = dimensionContext.width; var h = dimensionContext.height;
var g = ctx.createLinearGradient(0,0,0,h);
g.addColorStop(0, '#070a1d');
g.addColorStop(0.38, '#17103c');
g.addColorStop(1, '#071722');
ctx.fillStyle = g; ctx.fillRect(0,0,w,h);

var centerX = w * 0.5; var centerY = h * 0.42;

// Atmosphere glow (no road/lane shape)
var glow = ctx.createRadialGradient(centerX, centerY, 0, centerX, centerY, h * 0.95);
glow.addColorStop(0, 'rgba(110,80,255,0.20)');
glow.addColorStop(0.34, 'rgba(55,220,255,0.11)');
glow.addColorStop(1, 'rgba(0,0,0,0)');
ctx.fillStyle = glow; ctx.fillRect(0,0,w,h);

// Big passing hardwood silhouettes (strong parallax)
var trees = state.trees || [];
for (var t = 0; t < trees.length; t++) {
  var tr = trees[t];
  var py = h * 0.16 + tr.y * (h * 0.9);
  var depth = 0.35 + tr.y * 1.9;
  var spread = (0.22 + tr.lane * 0.48) * w * depth;
  var px = centerX + tr.side * spread;
  var trunkH = h * (tr.h * 1.35) * depth;
  var trunkW = Math.max(1.8, 3.4 * depth);
  var neon = tr.side < 0 ? 'rgba(65,245,255,0.24)' : 'rgba(238,95,255,0.22)';

  // trunk
  ctx.fillStyle = 'rgba(5,18,24,0.92)';
  ctx.fillRect(px - trunkW*0.5, py - trunkH, trunkW, trunkH);
  ctx.strokeStyle = neon; ctx.lineWidth = Math.max(0.8, 1.4 * depth);
  ctx.beginPath(); ctx.moveTo(px, py - trunkH); ctx.lineTo(px, py); ctx.stroke();

  // branch fans
  for (var b = 0; b < 4; b++) {
    var by = py - trunkH * (0.25 + b * 0.16);
    var bl = (10 + b * 5) * depth;
    ctx.beginPath();
    ctx.moveTo(px, by); ctx.lineTo(px + tr.side * bl, by - 5 * depth);
    ctx.moveTo(px, by + 2*depth); ctx.lineTo(px - tr.side * bl * 0.7, by - 3 * depth);
    ctx.stroke();
  }
}

// Full-frame snowflake starfield rushing toward viewer
var flakes = state.flakes || [];
ctx.save(); ctx.globalCompositeOperation = 'lighter';
for (var i = 0; i < flakes.length; i++) {
  var f = flakes[i];
  var persp = 1.0 / Math.max(0.05, f.z);
  var sx = centerX + f.x * w * 0.28 * persp;
  var sy = (f.y - 0.08) * h * 1.18;
  if (sx < -35 || sx > w + 35 || sy < -35 || sy > h + 35) continue;
  var len = Math.min(34, 2 + persp * 6.4);
  var wid = Math.min(5.0, 0.5 + persp * 0.85);
  var hue = (i % 2 === 0) ? 192 : 302;
  var a = Math.min(0.98, 0.15 + persp * 0.095);

  // primary streak
  ctx.strokeStyle = 'hsla(' + hue + ',100%,80%,' + a.toFixed(3) + ')';
  ctx.lineWidth = wid;
  ctx.beginPath();
  ctx.moveTo(sx, sy);
  ctx.lineTo(sx, sy + len);
  ctx.stroke();

  // tiny cross sparkle near head for snowflake feel
  if (persp > 6) {
    ctx.lineWidth = Math.max(0.8, wid * 0.45);
    ctx.beginPath();
    ctx.moveTo(sx - 2.2, sy + 1.6); ctx.lineTo(sx + 2.2, sy + 1.6);
    ctx.moveTo(sx, sy - 0.8); ctx.lineTo(sx, sy + 4.0);
    ctx.stroke();
  }
}
ctx.restore();

// Peripheral speed haze
for (var k = 0; k < 26; k++) {
  var left = (k % 2 === 0);
  var x0 = left ? (6 + (k%6)*5) : (w - 6 - (k%6)*5);
  var y0 = (k / 25) * h;
  ctx.strokeStyle = left ? 'rgba(65,245,255,0.12)' : 'rgba(235,90,255,0.11)';
  ctx.lineWidth = 1;
  ctx.beginPath();
  ctx.moveTo(x0, y0);
  ctx.lineTo(left ? x0 + 18 : x0 - 18, y0 + 14);
  ctx.stroke();
}
